#!/usr/bin/env bash
# owned-audience.sh — 平台风险分散 / Owned Audience 建设（抗平台依赖） SOP walkthrough for 内容创作者经济(Substack / Beehiiv / 公众号 / 知识星球 / 小报童 / Patreon — newsletter 写作 + 订阅制变现 + 受众沉淀 + 个人 IP).
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="内容创作者经济(Substack / Beehiiv / 公众号 / 知识星球 / 小报童 / Patreon — newsletter 写作 + 订阅制变现 + 受众沉淀 + 个人 IP)"
WORKFLOW="平台风险分散 / Owned Audience 建设（抗平台依赖）"

usage() {
  cat <<EOF
owned-audience.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./owned-audience.sh             # interactive
  ./owned-audience.sh --dry-run
  ./owned-audience.sh --json
  ./owned-audience.sh --explain
  ./owned-audience.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "平台风险分散 / Owned Audience 建设（抗平台依赖）" 工作流。

一句话: 从「受众和内容全押在一个平台账号上」到「核心资产(email 列表 + 自有域名)握在自己手里、平台只是分发渠道之一」。intake 把「鸡蛋分篮」列为本行硬约束,这是贯穿 #1/#2 全程的防御性 workflow。

入门 SOP 共 5 步, 失败模式自检 3 项。

相关心智模型:
  • 平台是聚合者,创作者是租户 — 资产要握在自己手里: newsletter / 创作者经济里,平台(Substack / 公众号)靠控制需求与分发赢,创作者在平台上是租户;真正的资产是「能带走的 email 列表 + 自有域名(海外)/ 私域回流(国内)
  • 「先免费建信任、再变现」的耐心模型: 这一行的资深人默认「受众信任 / 受众深度」是前置资产,变现是它的函数 — 顺序不能反:先把价值无偿给出去、把漏斗顶部做够宽,再谈收费 / 接广告 / 卖课。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**第一天就绑自有域名**:newsletter 用自己的域名(而非纯平台子域),让品牌和入口不属于平台。"
  "**确认 email 列表可导出**:选平台时就确认「订阅者邮箱能不能完整导出」——这是 owned audience 的命根(Substack / beehiiv / Ghost 都支持,封闭生态如公众号基本不支持,这是国内路径 #2 的结构性弱点)。"
  "**跨平台分发**:内容至少在「主阵地 + 1-2 个其他平台」同步存在,不把所有触点压在一处(海外:Substack + X/LinkedIn;国内:公众号 + 视频号/小红书)。"
  "**定期导出备份**:把 email 列表周期性导出存档,平台出事时能立即迁移。"
  "**把「平台关注数」和「自有受众」分开记账**:清楚哪些是「租来的流量」(平台粉丝)、哪些是「真资产」(可直接触达的 email / 私域)。"
)
declare -a FAILURE_MODES=(
  "**All-in 单一平台 + 把平台粉丝数当资产**:平台一次政策变动可让头部腰斩。避免:第一天绑自有域名 + 跨 ≥2 平台。"
  "**选了不能导出 email 的封闭平台**:被锁死无法迁移。避免:选平台时把「email 可导出」当硬指标(国内公众号此项天然不达标,需用私域回流补)。"
  "**平均用力铺一堆平台**:精力分散、每个都做不好。避免:1 主阵地 + 2-3 个有意义的备份,够了就停。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "owned-audience-walkthrough"
fi
